// Code node: "Code in JavaScript" (UPDATED)
// Adds:
// - years_experience_required (from LLM)
// - role_level_years (formula, LLM does NOT judge)
// - margin_min, margin_max (formula)
// Also updates buy/sell base-rate lookups to use years-based level if present.

function tryParseJson(str) {
  if (typeof str !== "string") return null;
  try { const obj = JSON.parse(str); if (obj && typeof obj === "object") return obj; } catch {}
  return null;
}

function extractAgentJson(raw) {
  if (raw && typeof raw === "object" && Array.isArray(raw.roles)) return raw;
  const candidates = [];
  if (typeof raw === "string") candidates.push(raw);
  if (raw?.output) candidates.push(raw.output);
  if (raw?.text) candidates.push(raw.text);
  if (raw?.message) candidates.push(raw.message);
  if (raw?.choices) raw.choices.forEach(c => candidates.push(c?.message?.content || ""));
  if (raw?.json) candidates.push(raw.json);
  if (raw?.data) candidates.push(raw.data);

  for (const c of candidates) {
    const parsed = tryParseJson(c);
    if (parsed?.roles) return parsed;
  }
  throw new Error("Could not parse AI Agent output (roles missing).");
}

function inferLocationGroup(countryRaw) {
  if (!countryRaw) return null;
  const c = String(countryRaw).toLowerCase();
  if (c.includes("germany") || c.includes("france") || c.includes("uk")) return "HIC";
  if (c.includes("nigeria") || c.includes("kenya") || c.includes("india")) return "MIC";
  if (c.includes("south sudan") || c.includes("somalia") || c.includes("haiti")) return "LIC";
  return null;
}

function computeScarcityTier(ids, level) {
  const set = new Set((ids || []).map(String));
  if (set.has("CROSS_CUT") || set.has("NICHE_LANG")) return "S4";
  if (set.has("ADV_QUANT") || set.has("ECON") || set.has("FC")) return "S3";
  if (!set.size && (level === "Junior" || level === "Intermediate")) return "S1";
  return "S2";
}

function computeValueTier(title, level) {
  const t = (title || "").toLowerCase();
  if (t.includes("team lead") || t.includes("project manager") || t.includes("key expert")) return "V3";
  if (level === "Expert" || level === "Senior") return "V2";
  if (level === "Junior" || level === "Intermediate") return "V1";
  return "V2";
}

const proj = extractAgentJson($json);

const projectId = proj.project_id || null;
const projectName = proj.project_name || null;
const clientName = proj.client_name_raw || null;
const clientDefaultMargin = proj.client_default_margin ?? null;
const country = proj.country || null;
const locationGroup = proj.location_group || inferLocationGroup(country);
const roles = proj.roles || [];

if (!roles.length) throw new Error("No roles[] found.");

const makeFormula = (expr) => `=${expr}`;

// Column letters based on your current structure:
// AD = target_sell (col 30)
// AE = years_experience_required (new col 31)
// AF = role_level_years (new col 32)
// AG = margin_min (new col 33)
// AH = margin_max (new col 34)

const items = roles.map((r) => {
  const roleId = r.role_id || "R?";
  const roleTitle = r.role_title || "";
  const roleLevel = r.role_level_required || "";
  const roleDays = r.role_days || "";
  const yearsReq = (r.role_years_required != null && !isNaN(Number(r.role_years_required)))
    ? Number(r.role_years_required)
    : "";

  const scarcity = computeScarcityTier(r.role_scarcity_ids, roleLevel);
  const value = computeValueTier(roleTitle, roleLevel);

  const scarcityLabel =
    scarcity === "S1" ? "S1 - Readily Available" :
    scarcity === "S2" ? "S2 - Baseline" :
    scarcity === "S3" ? "S3 - Scarce" :
    "S4 - Very Scarce";

  const valueLabel = `Value tier ${value} multiplier`;

  // ✅ NEW: role_level_years formula (Leader >10, Expert >6, Senior >3, else Junior)
  const fRoleLevelYears = makeFormula(
    `IF(INDEX($AE:$AE,ROW())="","",` +
      `IF(INDEX($AE:$AE,ROW())>10,"Leader",` +
        `IF(INDEX($AE:$AE,ROW())>6,"Expert",` +
          `IF(INDEX($AE:$AE,ROW())>3,"Senior","Junior")` +
        `)` +
      `)` +
    `)`
  );

  // Effective level for rate lookup:
  // Prefer years-based level (AF) if present, else fallback to ToR level (J).
  // Map Leader -> Expert (unless you add BUY_MIN_LEADER etc. later).
  const effLevel =
    `IF(INDEX($AF:$AF,ROW())<>"",INDEX($AF:$AF,ROW()),INDEX($J:$J,ROW()))`;
  const normLevel =
    `IF(UPPER(${effLevel})="LEADER","Expert",${effLevel})`;

  // Existing formulas (updated to use normLevel)
  const fClientBuying = makeFormula(
    `IF(INDEX($C:$C,ROW())="",` +
      `INDEX(Parameters!$B:$B,MATCH("CLIENT_FACTOR_DEFAULT",Parameters!$A:$A,0)),` +
      `IFERROR(` +
        `INDEX(Parameters!$B:$B,MATCH("CLIENT_FACTOR_"&INDEX($C:$C,ROW()),Parameters!$A:$A,0)),` +
        `INDEX(Parameters!$B:$B,MATCH("CLIENT_FACTOR_DEFAULT",Parameters!$A:$A,0))` +
      `)` +
    `)`
  );

  const fLocationFactor = makeFormula(
    `IF(INDEX($L:$L,ROW())="", "",` +
      `INDEX(Parameters!$B:$B,` +
        `MATCH("LOCATION_FACTOR_" & TRIM(LEFT(INDEX($L:$L,ROW()),FIND(" ",INDEX($L:$L,ROW()) & " ")-1)),Parameters!$A:$A,0)` +
      `)` +
    `)`
  );

  // ✅ UPDATED: base rates now use normLevel (years-based if present)
  const fBuyMin = makeFormula(
    `IF(${effLevel}="", "",` +
      `INDEX(Parameters!$B:$B, MATCH("BUY_MIN_" & UPPER(${normLevel}), Parameters!$A:$A, 0))` +
    `)`
  );

  const fBuyMax = makeFormula(
    `IF(${effLevel}="", "",` +
      `INDEX(Parameters!$B:$B, MATCH("BUY_MAX_" & UPPER(${normLevel}), Parameters!$A:$A, 0))` +
    `)`
  );

  const fSellMin = makeFormula(
    `IF(${effLevel}="", "",` +
      `INDEX(Parameters!$B:$B, MATCH("SELLING_BASE_" & UPPER(${normLevel}), Parameters!$A:$A, 0))` +
    `)`
  );

  const fCommitment = makeFormula(
    `IF(INDEX($Q:$Q,ROW())="", "",` +
      `INDEX(Parameters!$B:$B, MATCH(` +
        `IF(INDEX($Q:$Q,ROW())>100,"COMMITMENT_GT_100",` +
          `IF(INDEX($Q:$Q,ROW())>=50,"COMMITMENT_50_100",` +
            `IF(INDEX($Q:$Q,ROW())>=20,"COMMITMENT_20_50",` +
              `IF(INDEX($Q:$Q,ROW())>=10,"COMMITMENT_10_20","COMMITMENT_LT_10")` +
            `)` +
          `)` +
        `), Parameters!$A:$A, 0))` +
    `)`
  );

  const fScarcityFactor = makeFormula(
    `IF(INDEX($S:$S,ROW())="", "",` +
      `INDEX(Parameters!$B:$B, MATCH("SCARCITY_" & TRIM(LEFT(INDEX($S:$S,ROW()),FIND(" ",INDEX($S:$S,ROW()) & " ")-1)), Parameters!$A:$A, 0))` +
    `)`
  );

  const fValueFactor = makeFormula(
    `IF(INDEX($U:$U,ROW())="", "",` +
      `IFERROR(` +
        `INDEX(Parameters!$B:$B, MATCH("VALUE_" & TRIM(REGEXEXTRACT(INDEX($U:$U,ROW()),"(V[1-4])")), Parameters!$A:$A, 0))` +
      `, 1.0)` +
    `)`
  );

  const fAdjMinBuy = makeFormula(`INDEX($N:$N,ROW())*INDEX($R:$R,ROW())*INDEX($T:$T,ROW())*INDEX($V:$V,ROW())`);
  const fAdjMaxBuy = makeFormula(`INDEX($O:$O,ROW())*INDEX($R:$R,ROW())*INDEX($T:$T,ROW())*INDEX($V:$V,ROW())`);
  const fTargetBuy = makeFormula(`(INDEX($W:$W,ROW())+INDEX($X:$X,ROW()))/2`);
  const fMinCost = makeFormula(`INDEX($W:$W,ROW())*INDEX($Q:$Q,ROW())`);
  const fMaxCost = makeFormula(`INDEX($X:$X,ROW())*INDEX($Q:$Q,ROW())`);
  const fMinSell = makeFormula(`INDEX($P:$P,ROW())`);
  const fAdjSell = makeFormula(`INDEX($AB:$AB,ROW())*INDEX($M:$M,ROW())*INDEX($T:$T,ROW())*INDEX($V:$V,ROW())`);
  const fTargetSell = makeFormula(`MAX(INDEX($AB:$AB,ROW()),INDEX($AC:$AC,ROW()))`);

  // ✅ NEW: margins (computed from target_sell vs adjusted buy rates)
  // min margin = sell vs worst-case buy (adjusted_max_buy)
  const fMarginMin = makeFormula(
    `IF(OR(INDEX($AD:$AD,ROW())="",INDEX($X:$X,ROW())=""),"", INDEX($AD:$AD,ROW())/INDEX($X:$X,ROW())-1)`
  );
  // max margin = sell vs best-case buy (adjusted_min_buy)
  const fMarginMax = makeFormula(
    `IF(OR(INDEX($AD:$AD,ROW())="",INDEX($W:$W,ROW())=""),"", INDEX($AD:$AD,ROW())/INDEX($W:$W,ROW())-1)`
  );

  return {
    json: {
      project_id: projectId,
      project_name: projectName,
      client_name: clientName,
      language_req: (r.role_languages_required || []).join(", "),
      country: country,

      role_id: roleId,
      role_title: roleTitle,

      client_buying_factor: fClientBuying,
      client_default_margin: clientDefaultMargin,

      role_level: roleLevel,
      "role_category/family": null,

      location_group: locationGroup,
      location_factor: fLocationFactor,

      buying_rate_min: fBuyMin,
      buying_rate_max: fBuyMax,
      selling_rate_min: fSellMin,

      role_days: roleDays,
      commitment_adj: fCommitment,

      scarcity_tier: scarcityLabel,
      scarcity_factor: fScarcityFactor,
      value_tier: valueLabel,
      value_factor: fValueFactor,

      adjusted_min_buy: fAdjMinBuy,
      adjusted_max_buy: fAdjMaxBuy,
      target_buy: fTargetBuy,
      min_cost: fMinCost,
      max_cost: fMaxCost,
      min_sell: fMinSell,
      adjusted_sell: fAdjSell,
      target_sell: fTargetSell,

      // ✅ NEW columns
      years_experience_required: yearsReq,
      role_level_years: fRoleLevelYears,
      margin_min: fMarginMin,
      margin_max: fMarginMax,
    }
  };
});

return items;

